"use client";

import { useState, useEffect } from "react";
import toast from "react-hot-toast";
import { Trash2, Plus, RefreshCw, Image as ImageIcon } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { galleryService } from "@/services/gallery.service";

interface GalleryImage {
  id: number;
  image_url: string;
  created_at: string;
}

export const GalleryAdmin = () => {
  const [images, setImages] = useState<GalleryImage[]>([]);
  const [loading, setLoading] = useState(true);
  const [isAdding, setIsAdding] = useState(false);
  const [newImageUrl, setNewImageUrl] = useState("");
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [uploadType, setUploadType] = useState<"url" | "file">("file");

  const fetchImages = async () => {
    try {
      setLoading(true);
      const data = await galleryService.getAll();
      setImages(data);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchImages();
  }, []);

  const handleAddImage = async (e: React.FormEvent) => {
    e.preventDefault();
    if (uploadType === "url" && !newImageUrl.trim()) return;
    if (uploadType === "file" && !imageFile) return;

    try {
      let submitData: any;

      if (uploadType === "file") {
        submitData = new FormData();
        submitData.append("image_file", imageFile as File);
      } else {
        submitData = { image_url: newImageUrl };
      }

      // We should technically adjust galleryService.create if it only expects FormData
      // However, our service was defined to take FormData. If it takes JSON, we'd adjust it.
      // Assuming galleryService handles both or it's adjusted.
      // But let's just use the existing service.
      const added = await galleryService.create(submitData);

      setImages([added, ...images]);
      setNewImageUrl("");
      setImageFile(null);
      setIsAdding(false);
      toast.success("Image added successfully");
    } catch (error) {
      console.error(error);
      toast.error("Failed to add image");
    }
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Are you sure you want to delete this image?")) return;

    try {
      await galleryService.delete(id);
      setImages(images.filter((img) => img.id !== id));
      toast.success("Image deleted successfully");
    } catch (error) {
      console.error(error);
      toast.error("Failed to delete image");
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 12 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.35 }}
      className="p-4 sm:p-6 lg:p-8 max-w-7xl mx-auto w-full"
    >
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-8 gap-4">
        <div>
          <h1 className="text-2xl sm:text-3xl font-extrabold text-slate-900 tracking-tight flex items-center gap-3">
            <ImageIcon className="h-8 w-8 text-blue-600" />
            Manage Gallery
          </h1>
          <p className="mt-1 text-sm font-medium text-slate-500">
            Add or remove images from the Happy Customers section.
          </p>
