                      <p className="text-blue-600 font-black text-lg bg-blue-50 w-fit px-3 py-1 rounded-lg">
                        {selectedCar}
                      </p>
                    </div>

                    <form onSubmit={handleSubmit} className="space-y-4">
                      <div>
